import { NextResponse } from "next/server";
import { getServerSession } from "next-auth/next";
import { authOptions } from "@/app/api/auth/[...nextauth]/route";
import { prisma } from "@/lib/prisma";
import path from "path";
import { readFile, stat, writeFile } from "fs/promises";
import { enqueueKnowledgeIngestion, processKnowledgeQueueBatch } from "@/lib/rag/queue";
import { ingestionService } from "@/lib/rag/ingestion";

const MAX_EDIT_OPERATIONS = 200;

function isSpreadsheetFile(fileName: string) {
  return /\.(xlsx|xlsm)$/i.test(fileName);
}

function resolveWorkbookType(fileName: string) {
  return /\.xlsm$/i.test(fileName) ? "xlsm" : "xlsx";
}

function sanitizeWorksheetText(value: string) {
  return value.replace(/[\u0000-\u0008\u000B\u000C\u000E-\u001F]/g, "").trim();
}

function extractSpreadsheetText(buffer: Buffer, XLSX: any) {
  const workbook = XLSX.read(buffer, { type: "buffer" });
  const selectedSheets = workbook.SheetNames.slice(0, 4);
  const blocks: string[] = [];

  for (const sheetName of selectedSheets) {
    const sheet = workbook.Sheets[sheetName];
    if (!sheet) continue;

    const rows = XLSX.utils.sheet_to_json<Array<string | number | boolean | null>>(sheet, {
      header: 1,
      raw: false,
      blankrows: false,
    });

    const lines = rows
      .slice(0, 220)
      .map((row) => row.map((cell) => (cell ?? "").toString().trim()).join(" | ").trim())
      .filter(Boolean);

    if (lines.length > 0) {
      blocks.push(`[HOJA: ${sheetName}]\n${lines.join("\n")}`);
    }
  }

  return sanitizeWorksheetText(blocks.join("\n\n"));
}

function normalizeFilePath(fileUrl: string) {
  const normalizedFileUrl = fileUrl.trim();
  if (!normalizedFileUrl.startsWith("/uploads/")) {
    throw new Error("Archivo no soportado para previsualizacion");
  }
  const fileName = decodeURIComponent(normalizedFileUrl.split("/").pop() || "");
  if (!isSpreadsheetFile(fileName)) {
    throw new Error("Solo se pueden previsualizar archivos .xlsx y .xlsm");
  }
  const localPath = path.join(process.cwd(), "public", normalizedFileUrl.replace(/^\//, ""));
  return { normalizedFileUrl, fileName, localPath };
}

async function assertBusinessAccessOrThrow(businessId: string, email: string) {
  const business = await prisma.business.findFirst({
    where: {
      id: businessId,
      user: { email },
    },
    select: { id: true },
  });

  if (!business) {
    throw new Error("Business not found or unauthorized");
  }
}

function mapSheetPreview(sheet: any, XLSX: any) {
  const rows = XLSX.utils.sheet_to_json<Array<string | number | boolean | null>>(sheet, {
    header: 1,
    raw: false,
    blankrows: false,
  });

  const header = (rows[0] || []).map((cell: string | number | boolean | null, idx: number) => {
    const value = (cell ?? "").toString().trim();
    return value || `Col ${idx + 1}`;
  });

  const bodyRows = rows
    .slice(1, 101)
    .map((row: Array<string | number | boolean | null>) => row.map((cell: string | number | boolean | null) => (cell ?? "").toString()));

  return {
    rowCount: rows.length,
    headers: header,
    rows: bodyRows,
  };
}

export async function GET(req: Request) {
  try {
    const session = await getServerSession(authOptions);
    if (!session?.user?.email) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const { searchParams } = new URL(req.url);
    const businessId = searchParams.get("businessId");
    const fileUrl = searchParams.get("fileUrl");

    if (!businessId || !fileUrl) {
      return NextResponse.json({ error: "businessId y fileUrl son requeridos" }, { status: 400 });
    }

    await assertBusinessAccessOrThrow(businessId, session.user.email);
    const { normalizedFileUrl, fileName, localPath } = normalizeFilePath(fileUrl);
    const buffer = await readFile(localPath);
    const XLSX = require("xlsx");
    const workbook = XLSX.read(buffer, { type: "buffer" });
    const stats = await stat(localPath);

    const sheets = workbook.SheetNames.slice(0, 8).map((sheetName: string) => {
      const sheet = workbook.Sheets[sheetName];
      return {
        name: sheetName,
        ...mapSheetPreview(sheet, XLSX),
      };
    });

    return NextResponse.json({
      success: true,
      data: {
        fileName,
        fileUrl: normalizedFileUrl,
        modifiedAt: stats.mtime.toISOString(),
        sheets,
      },
    });
  } catch (error) {
    const message = error instanceof Error ? error.message : "Internal Error";
    const status = message === "Business not found or unauthorized" ? 404 : message.includes("previsualizacion") || message.includes(".xlsx") ? 400 : 500;
    console.error("[Knowledge Preview] Error:", error);
    return NextResponse.json({ error: message === "Internal Error" ? "Internal Error" : message }, { status });
  }
}

export async function PATCH(req: Request) {
  try {
    const session = await getServerSession(authOptions);
    if (!session?.user?.email) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const body = await req.json().catch(() => ({}));
    const businessId = typeof body.businessId === "string" ? body.businessId : "";
    const fileUrl = typeof body.fileUrl === "string" ? body.fileUrl : "";
    const edits = Array.isArray(body.edits) ? body.edits : [];

    if (!businessId || !fileUrl || edits.length === 0) {
      return NextResponse.json({ error: "businessId, fileUrl y edits son requeridos" }, { status: 400 });
    }

    if (edits.length > MAX_EDIT_OPERATIONS) {
      return NextResponse.json({ error: `Demasiadas ediciones en una sola solicitud (max ${MAX_EDIT_OPERATIONS})` }, { status: 400 });
    }

    await assertBusinessAccessOrThrow(businessId, session.user.email);
    const { normalizedFileUrl, fileName, localPath } = normalizeFilePath(fileUrl);

    const XLSX = require("xlsx");
    const originalBuffer = await readFile(localPath);
    const workbook = XLSX.read(originalBuffer, { type: "buffer" });

    for (const edit of edits) {
      const sheetName = typeof edit?.sheetName === "string" ? edit.sheetName : "";
      const rowIndex = Number(edit?.rowIndex);
      const colIndex = Number(edit?.colIndex);
      const value = edit?.value == null ? "" : String(edit.value);

      if (!sheetName || !Number.isInteger(rowIndex) || !Number.isInteger(colIndex) || rowIndex < 0 || colIndex < 0) {
        return NextResponse.json({ error: "Formato de edit invalido" }, { status: 400 });
      }
      if (value.length > 2000) {
        return NextResponse.json({ error: "El valor de celda excede el limite de 2000 caracteres" }, { status: 400 });
      }

      const sheet = workbook.Sheets[sheetName];
      if (!sheet) {
        return NextResponse.json({ error: `Hoja no encontrada: ${sheetName}` }, { status: 400 });
      }

      const cellRef = XLSX.utils.encode_cell({ r: rowIndex, c: colIndex });
      sheet[cellRef] = { t: "s", v: value };

      const currentRange = sheet["!ref"] ? XLSX.utils.decode_range(sheet["!ref"]) : { s: { r: 0, c: 0 }, e: { r: rowIndex, c: colIndex } };
      currentRange.e.r = Math.max(currentRange.e.r, rowIndex);
      currentRange.e.c = Math.max(currentRange.e.c, colIndex);
      sheet["!ref"] = XLSX.utils.encode_range(currentRange);
    }

    const outputBuffer: Buffer = XLSX.write(workbook, {
      type: "buffer",
      bookType: resolveWorkbookType(fileName),
    });

    await writeFile(localPath, outputBuffer);

    const extractedText = extractSpreadsheetText(outputBuffer, XLSX);
    if (!extractedText) {
      return NextResponse.json({ error: "No se pudo extraer texto del archivo actualizado" }, { status: 422 });
    }

    await prisma.$executeRawUnsafe(
      `DELETE FROM "KnowledgeItem" WHERE "businessId" = $1 AND metadata->>'fileUrl' = $2`,
      businessId,
      normalizedFileUrl
    );

    const enqueue = await enqueueKnowledgeIngestion({
      businessId,
      text: `[EXCEL: ${fileName}]\n${extractedText}`,
      metadata: {
        fileName,
        fileType: /\.xlsm$/i.test(fileName) ? "application/vnd.ms-excel.sheet.macroEnabled.12" : "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        fileUrl: normalizedFileUrl,
        source: "excel_editor",
        sourceId: normalizedFileUrl,
      },
    });

    if (enqueue.missingQueueTable) {
      await ingestionService.ingestText(businessId, `[EXCEL: ${fileName}]\n${extractedText}`, {
        fileName,
        fileType: /\.xlsm$/i.test(fileName) ? "application/vnd.ms-excel.sheet.macroEnabled.12" : "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        fileUrl: normalizedFileUrl,
        source: "excel_editor",
        sourceId: normalizedFileUrl,
      });
    } else {
      void processKnowledgeQueueBatch(1).catch((error) => {
        console.error("[Knowledge Preview PATCH] Queue kickoff error:", error);
      });
    }

    const updatedStats = await stat(localPath);
    return NextResponse.json({
      success: true,
      message: "Archivo actualizado correctamente",
      data: {
        fileUrl: normalizedFileUrl,
        modifiedAt: updatedStats.mtime.toISOString(),
        reindexed: true,
        queued: !enqueue.missingQueueTable,
        jobId: enqueue.job?.id || null,
      },
    });
  } catch (error) {
    const message = error instanceof Error ? error.message : "Internal Error";
    const status = message === "Business not found or unauthorized" ? 404 : message.includes("previsualizacion") || message.includes(".xlsx") || message.includes(".xlsm") ? 400 : 500;
    console.error("[Knowledge Preview PATCH] Error:", error);
    return NextResponse.json({ error: message === "Internal Error" ? "Internal Error" : message }, { status });
  }
}

